#include "electromagnet.h"
#include <Arduino.h>
#define EMAG_PIN 25
void emag_setup(){pinMode(EMAG_PIN,OUTPUT);Serial.println("[emag] OK");}
void emag_on(){digitalWrite(EMAG_PIN,HIGH);}
void emag_off(){digitalWrite(EMAG_PIN,LOW);}
void emag_pulse(uint16_t ms){emag_on();delay(ms);emag_off();}
